package com.example.bankingapp;

import androidx.appcompat.app.AppCompatActivity;
import android.os.Bundle;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

public class MainActivity extends AppCompatActivity {

    private EditText accountNumberEditText;
    private EditText transactionAmountEditText;
    private TextView balanceTextView;
    private Button processTransactionButton;

    private double currentBalance = 1000.0; // Initial balance for demonstration

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        accountNumberEditText = findViewById(R.id.accountNumberEditText);
        transactionAmountEditText = findViewById(R.id.transactionAmountEditText);
        balanceTextView = findViewById(R.id.balanceTextView);
        processTransactionButton = findViewById(R.id.processTransactionButton);

        updateBalanceDisplay();

        processTransactionButton.setOnClickListener(view -> {
            String accountNumber = accountNumberEditText.getText().toString();
            double transactionAmount;

            try {
                transactionAmount = Double.parseDouble(transactionAmountEditText.getText().toString());
            } catch (NumberFormatException e) {
                Toast.makeText(MainActivity.this, "Invalid transaction amount", Toast.LENGTH_SHORT).show();
                return;
            }

            if (accountNumber.isEmpty() || transactionAmount <= 0) {
                Toast.makeText(MainActivity.this, "Please enter valid account number and transaction amount", Toast.LENGTH_SHORT).show();
                return;
            }

            processTransaction(transactionAmount);
        });
    }

    private void updateBalanceDisplay() {
        balanceTextView.setText("Current Balance: $" + String.format("%.2f", currentBalance));
    }

    private void processTransaction(double amount) {
        if (amount > currentBalance) {
            Toast.makeText(this, "Insufficient funds", Toast.LENGTH_SHORT).show();
            return;
        }

        currentBalance -= amount;
        updateBalanceDisplay();

        // For demonstration purposes, assume transaction is always successful
        Toast.makeText(this, "Transaction processed successfully", Toast.LENGTH_SHORT).show();
    }
}